import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.CnqOxlWO.js";const p=JSON.parse('{"title":"Chat","description":"","frontmatter":{},"headers":[],"relativePath":"features/chat.md","filePath":"features/chat.md","lastUpdated":1773376681000}'),i={name:"features/chat.md"};function s(r,e,l,h,c,d){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="chat" tabindex="-1">Chat <a class="header-anchor" href="#chat" aria-label="Permalink to &quot;Chat&quot;">​</a></h1><p>The chat page is where you spend most of your time in ClawdSaber.</p><p>As long as an agent is selected in the sidebar and the Gateway is running, you can start a conversation immediately.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><h3 id="_1-select-an-agent" tabindex="-1">1. Select an Agent <a class="header-anchor" href="#_1-select-an-agent" aria-label="Permalink to &quot;1. Select an Agent&quot;">​</a></h3><p>If the chat page shows &quot;No available agent&quot;, you need to create one first.</p><p>Go to:</p><ul><li><a href="/clawdsaber-docs/features/templates-and-market.html">Templates</a> — create from a built-in or downloaded template</li><li><a href="/clawdsaber-docs/features/templates-and-market.html">Agent Market</a> — browse and download community templates</li></ul><h3 id="_2-gateway-must-be-running" tabindex="-1">2. Gateway Must Be Running <a class="header-anchor" href="#_2-gateway-must-be-running" aria-label="Permalink to &quot;2. Gateway Must Be Running&quot;">​</a></h3><p>If the page shows a &quot;Gateway not running&quot; warning, chat will not work.</p><p>You can:</p><ul><li>Re-run the setup wizard to check the environment</li><li>Click the Gateway restart button in the top bar</li><li>See the <a href="/clawdsaber-docs/settings/faq.html">FAQ</a> for troubleshooting</li></ul><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><p>The toolbar at the top of the chat page provides session management:</p><ul><li><strong>Current agent name</strong> — shows which agent you are chatting with</li><li><strong>Session dropdown</strong> — switch between sessions or view session history</li><li><strong>New Session</strong> — start a fresh conversation without prior context</li><li><strong>Delete Session</strong> — remove the current session</li><li><strong>Refresh</strong> — reload the chat history</li><li><strong>Show Thinking</strong> — toggle visibility of the model&#39;s reasoning process</li></ul><h3 id="sessions" tabindex="-1">Sessions <a class="header-anchor" href="#sessions" aria-label="Permalink to &quot;Sessions&quot;">​</a></h3><p>Each agent has its own list of sessions.</p><p>You can:</p><ul><li>Switch to a previous session to continue an older conversation</li><li>Keep multiple sessions for different topics</li><li>Delete sessions you no longer need</li></ul><h3 id="new-session" tabindex="-1">New Session <a class="header-anchor" href="#new-session" aria-label="Permalink to &quot;New Session&quot;">​</a></h3><p>If you do not want your new question to be influenced by prior context, click <strong>New Session</strong> to start clean.</p><h3 id="show-thinking" tabindex="-1">Show Thinking <a class="header-anchor" href="#show-thinking" aria-label="Permalink to &quot;Show Thinking&quot;">​</a></h3><p>When enabled, messages may display additional information:</p><ul><li>Thinking / reasoning fragments</li><li>Tool calls and their results</li><li>Intermediate processing steps</li></ul><p>Not every response contains thinking content. If you enable it and see nothing extra, that simply means the model did not expose any reasoning for that particular reply.</p><h2 id="input-area" tabindex="-1">Input Area <a class="header-anchor" href="#input-area" aria-label="Permalink to &quot;Input Area&quot;">​</a></h2><p>The input area supports more than plain text.</p><p>You can:</p><ul><li>Type a message and press <strong>Enter</strong> to send</li><li>Press <strong>Shift + Enter</strong> to insert a new line</li><li>Click the paperclip icon to select files</li><li>Drag files into the input area</li><li>Paste images or files directly</li></ul><h3 id="attachments" tabindex="-1">Attachments <a class="header-anchor" href="#attachments" aria-label="Permalink to &quot;Attachments&quot;">​</a></h3><ul><li>Images display a thumbnail preview before sending</li><li>Other files show the filename, size, and a type icon</li><li>Files are staged locally before being sent</li></ul><p>If an attachment is still processing, the send button will be temporarily disabled. This is normal.</p><h2 id="responses" tabindex="-1">Responses <a class="header-anchor" href="#responses" aria-label="Permalink to &quot;Responses&quot;">​</a></h2><p>ClawdSaber uses streaming output.</p><ul><li>Responses appear incrementally as they are generated</li><li>You do not have to wait for the full reply to appear at once</li><li>Click the <strong>Stop</strong> button to interrupt generation at any time</li></ul><p>Messages support Markdown rendering, so code blocks, lists, tables, and other common formatting display correctly.</p><h2 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h2><p>If an error occurs during chat, an error bar appears at the bottom of the page.</p><p>To troubleshoot:</p><ol><li>Read the error message.</li><li>Refresh the chat.</li><li>Confirm the agent has a model assigned.</li><li>Confirm your account has sufficient credits.</li><li>Confirm the Gateway is running.</li></ol><p>If the agent never responds, start by checking the model in <a href="/clawdsaber-docs/features/agent-config.html">Agent Configuration</a>.</p>',41)])])}const g=a(i,[["render",s]]);export{p as __pageData,g as default};
